// DeepSeek returns JSON inside choices[0].message.content.

const raw =
  $json.choices &&
  Array.isArray($json.choices) &&
  $json.choices[0] &&
  $json.choices[0].message &&
  typeof $json.choices[0].message.content === 'string'
    ? $json.choices[0].message.content.trim()
    : '';

if (!raw) {
  throw new Error('LLM response is empty or missing choices[0].message.content');
}

// Clean markdown code fences and DeepSeek <think> tags
const cleaned = raw
  // remove ```json and ``` fences
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  // remove DeepSeek r1 thinking blocks if present
  .replace(/<think>[\\s\\S]*?<\\/think>/gi, '')
  .trim();

let bundle;

try {
  bundle = JSON.parse(cleaned);
} catch (err) {
  throw new Error(
    'Failed to parse LLM JSON: ' +
      err.message +
      '\nRaw content (first 500 chars):\n' +
      cleaned.slice(0, 500)
  );
}

// Expecting shape:
// {
//   "lesson": { "slug": "...", "title": "...", "topic": "...", "level": 0 },
//   "questions": [ ... ]
// }
const lesson = bundle.lesson || {};
const questions = Array.isArray(bundle.questions) ? bundle.questions : [];

const metaNode = $node['Set – Lesson Metadata'].json || {};

return questions.map((q, index) => ({
  json: {
    // lesson metadata (fallback-safe)
    lesson_slug: lesson.slug || metaNode.lesson_slug,
    lesson_title: lesson.title || metaNode.lesson_title,
    topic: lesson.topic || metaNode.topic,
    level:
      typeof lesson.level === 'number'
        ? lesson.level
        : metaNode.level,

    // question info
    question: q.question,
    answer: q.answer,
    difficulty: typeof q.difficulty === 'number' ? q.difficulty : 1,
    category: q.category || 'unspecified',
    question_type: q.question_type || 'short_answer',
    source: 'baseline',
    index,
  }
}));

