const raw = $json.choices?.[0]?.message?.content || "";
const cleaned = raw
  .replace(/```json/gi, "")
  .replace(/```/g, "")
  .replace(/<think>[\s\S]*?<\/think>/gi, "")
  .trim();

return [
  {
    json: {
      summary: cleaned
    }
  }
];

// Take raw chunk
let text = ($json.lesson_text || "").toString();

// Clean & shrink aggressively for llama3.2:1b stability
text = text
  .replace(/\r?\n+/g, " ")
  .replace(/\s+/g, " ")
  .replace(/\[.*?\]\(.*?\)/g, "")
  .replace(/[#*_`>~=-]/g, "")
  .trim()
  .slice(0, 600);   // HARD limit

return [
  {
    json: {
      ...$json,
      safe_text: text
    }
  }
];
